const deal = input.opportunity;
const eventNameMap = {
  QUALIFIED: "qualify_lead",
  WON: "lead_won",
  LOST: "lead_rejected",
};
const eventName = eventNameMap[deal.stage];
if (!eventName || !deal.idOid) return { skip: true };

const camelToSnake = (s) => s.replace(/[A-Z]/g, (m) => "_" + m.toLowerCase());
const now = new Date();
const idEvent = crypto.randomUUID();

return {
  skip: false,
  payload: {
    event_name: eventName,
    id_event: idEvent,
    id_oid: deal.idOid,
    id_crm_lead: deal.id,
    src_system: "crm",
    time_occurred_iso_utc: now.toISOString(),
    time_occurred_unix_s: Math.floor(now.getTime() / 1000),
    time_occurred_unix_us: now.getTime() * 1000,
    biz_product: camelToSnake(deal.bizProduct || ""),
    biz_source: camelToSnake(deal.bizSource || ""),
    ...(eventName === "lead_won" ? { biz_value: deal.amount, biz_currency: "PLN" } : {}),
  },
  idEvent: idEvent,
  now: now.toISOString(),
};
